import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return base premium plus processing fee for a single sword");
    it.todo("should return base premium plus processing fee for a single amulet");
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for an item with enchantment level >= 5");
    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
    it.todo("should add 10% surcharge for first insurance (0 prior contracts)");
    it.todo("should apply 15% discount for subsequent contracts (>= 1 prior contract)");
    it.todo("should sum premiums for multiple items");
    it.todo("should apply bundle discount for 3 alike components");
  });

  describe("claim", () => {
    it.todo("should deduct 100G deductible from damage amount");
    it.todo("should reimburse 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across multiple claims");
  });
});

