export type Customer = {
  yearsWithMHPCO: number;
  priorContracts: number;
};

export type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.10;

const roundUp = (n: number): number => Math.ceil(Math.round(n * 100) / 100);

export const quote = (customer: Customer, items: Item[]): number => {
  const basePremium = BASE_PREMIUMS[items[0].type];
  return roundUp(basePremium * (1 + FIRST_INSURANCE_SURCHARGE)) + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

